package paladin

import "github.com/wowsims/tbc/sim/core"

// Righteous Fury
// https://www.wowhead.com/tbc/spell=25780
//
// Increases the threat generated by your Holy spells by 60%.
// Improved Righteous Fury increases the threat bonus by 16/33/50% (i.e. 60% * 1.5 = 90% at rank 3).
func (paladin *Paladin) registerRighteousFury() {
	actionID := core.ActionID{SpellID: 25780}

	// Base RF = 60% threat. Improved RF multiplies this by (1 + rank/6):
	// Rank 0: 60%, Rank 1: 70%, Rank 2: 80%, Rank 3: 90%
	threatBonus := 0.6 * (1 + float64(paladin.Talents.ImprovedRighteousFury)/6)

	rfAura := paladin.RegisterAura(core.Aura{
		Label:    "Righteous Fury",
		ActionID: actionID,
		Duration: core.NeverExpires,
	}).AttachSpellMod(core.SpellModConfig{
		Kind:       core.SpellMod_ThreatMultiplier_Pct,
		School:     core.SpellSchoolHoly,
		FloatValue: threatBonus,
	})

	paladin.RighteousFury = paladin.RegisterSpell(core.SpellConfig{
		ActionID:       actionID,
		SpellSchool:    core.SpellSchoolHoly,
		ProcMask:       core.ProcMaskEmpty,
		Flags:          core.SpellFlagAPL | core.SpellFlagHelpful,
		ClassSpellMask: SpellMaskRighteousFury,

		Cast: core.CastConfig{
			DefaultCast: core.Cast{
				GCD: core.GCDDefault,
			},
		},

		ApplyEffects: func(sim *core.Simulation, _ *core.Unit, spell *core.Spell) {
			rfAura.Activate(sim)
		},

		RelatedSelfBuff: rfAura,
	})
}
